}

function isTransactionReceipt(x: unknown): x is { status: number } {
  if (typeof x === "object" && x !== null && "status" in x) {
    const status = x.status;

    // this means we only support ethers's receipts for now; adding support for
    // raw receipts, where the status is an hexadecimal string, should be easy
    // and we can do it if there's demand for that
    return typeof status === "number";
  }

  return false;
}

public async getTransactionCount(
  address: AddressLike,
  blockTag?: BlockTag | undefined,
): Promise<number> {
  const resolvedAddress = await this.#getAddress(address);
  const resolvedBlockTag = await this.#getBlockTag(blockTag);
  const rpcBlockTag = this.#getRpcBlockTag(resolvedBlockTag);

  const transactionCount = await this.#hardhatProvider.request({
    method: "eth_getTransactionCount",
    params: [resolvedAddress, rpcBlockTag],
  });

  return Number(transactionCount);
}

