#convertHardhatContractToViemContract(
  connection: NetworkConnection<ChainTypeT>,
  future:
    | NamedArtifactContractDeploymentFuture<string>
    | NamedArtifactLibraryDeploymentFuture<string>
    | NamedArtifactContractAtFuture<string>,
