async function resolveParametersFromModuleName(
  moduleName: string,
  ignitionPath: string,
): Promise<DeploymentParameters | undefined> {
  const files = await readdir(ignitionPath);
  const configFilename = `${moduleName}.config.json`;

  return files.includes(configFilename)
    ? await readDeploymentParameters(path.resolve(ignitionPath, configFilename))
    : undefined;
}

function isInModuleDirectory(modulesDirectory: string, modulePath: string) {
  const resolvedModulesDirectory = path.resolve(modulesDirectory);
  const moduleRelativeToModuleDir = path.relative(
    resolvedModulesDirectory,
    modulePath,
  );

  return (
    !moduleRelativeToModuleDir.startsWith("..") &&
    !path.isAbsolute(moduleRelativeToModuleDir)
  );
}

function deriveMasterKeyFromKeystore({
  password,
  encryptedKeystore,
}: {
  password: string;
  encryptedKeystore: EncryptedKeystore;
}): Uint8Array {
  const salt = hexToBytes(encryptedKeystore.crypto.masterKeyDerivation.salt);

  return deriveMasterKey({ password, salt });
}

function doesKeyExist({
  masterKey,
  encryptedKeystore,
  key,
}: {
  masterKey: Uint8Array;
  encryptedKeystore: EncryptedKeystore;
  key: string;
}): boolean {
  validateHmac({ masterKey, encryptedKeystore });
  return Object.keys(encryptedKeystore.secrets).includes(key);
}

public async writeJsonFile(
  absolutePathToFile: string,
  keystoreFile: EncryptedKeystore,
): Promise<void> {
  // First write to a temporary file, then move it to minimize the risk of file corruption
  const tmpPath = `${absolutePathToFile}.tmp`;
  await writeJsonFile(tmpPath, keystoreFile);
  return await move(tmpPath, absolutePathToFile);
}

